import{_ as e,c as i,a,o as n}from"./app-CEcM0piI.js";const l={};function d(p,s){return n(),i("div",null,s[0]||(s[0]=[a(`<p>相比于js,ts将一些运行时错误前置到静态错误检查了</p><p>ts的组件需要先通过npm下载</p><p>下载ts相关包</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm i typescript -g</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="命令" tabindex="-1"><a class="header-anchor" href="#命令"><span>命令</span></a></h3><p>将ts文件编译成js文件 文件名可带后缀也可不带</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>tsc 文件名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="自动化编译" tabindex="-1"><a class="header-anchor" href="#自动化编译"><span>自动化编译</span></a></h4><p>tsconfig.json常见属性</p><table><thead><tr><th>属性</th><th>作用</th></tr></thead><tbody><tr><td>noEmitOnError</td><td>当出现静态错误是是否提交,如果提交当发生静态错误是对应编译的js文件也会延续错误</td></tr><tr><td>target</td><td>编译目标js文件的标准</td></tr><tr><td>experimentalDecorators</td><td>实验性装饰器是否打开</td></tr></tbody></table><ol><li>创建初始化文件 生成tsconfig.json文件 该文件用于指定要自动化编译的内容,如es标准等</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>tsc --init</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>监视需要编译的文件 将要自动编译的文件设为监视,当被监视的文件发生更改就自动编译 可以不指定文件名,不指定文件名表示监视当前目录所有文件</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>tsc --watch 文件名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="类型定义" tabindex="-1"><a class="header-anchor" href="#类型定义"><span>类型定义</span></a></h1><p>被类型定义的变量无法接收定义类型的其他类型</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let a: string;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>a=1; // error</span></span>
<span class="line"><span>a=&#39;hello&#39;; // ok</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>类型定义函数参数和返回值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function add(x:number,y:number):number{</span></span>
<span class="line"><span>  return x+y;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let res=add(1,2);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="字面量类型" tabindex="-1"><a class="header-anchor" href="#字面量类型"><span>字面量类型</span></a></h3><p>限定一个变量的字面量类型后该变量只能接收对应的字面量</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let b=&#39;hello&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>b=&#39;world&#39;; // error</span></span>
<span class="line"><span>b=&#39;hello&#39;; // ok</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="新增数据类型" tabindex="-1"><a class="header-anchor" href="#新增数据类型"><span>新增数据类型</span></a></h1><p>除了js基本的类型之外,ts还新增了一些数据类型</p><ul><li>any</li><li>unknown</li><li>never</li><li>void</li><li>tuple</li><li>enum 两个用于自定义类型的方式</li><li>type</li><li>interface</li></ul><h3 id="ts提供的基础类型" tabindex="-1"><a class="header-anchor" href="#ts提供的基础类型"><span>ts提供的基础类型</span></a></h3><ol><li>原始类型VS包装对象</li></ol><ul><li>原始类型：如number、string、boolean，在JavaScript 中是简单数据类型，它们在内存中占用空间少，处理速度快。</li><li>包装对象：如Number对象、String对象、Boolean 对象，是复杂类型，在内存中占用更多空间，在日常开发时很少由开发人员自己创建包装对象。</li></ul><ol><li>自动装箱：JavaScript在必要时会自动将原始类型包装成对象，以便调用方法或访问属性</li></ol><p>在js中基础数据类型都是大写开头的,如:String ts中推荐使用基础数据类型小写开头的,如:string 他们的不同点是string是基元,而String是string的包装类</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let str1: string//TS官方推荐的写法</span></span>
<span class="line"><span>str1 = &#39;hello&#39;</span></span>
<span class="line"><span>str1 = new String(&#39;hello&#39;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let str2: String</span></span>
<span class="line"><span>str2 = &#39;hello&#39;</span></span>
<span class="line"><span>str2 = new String(&#39;hello&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>对于限定类型为string的变量,它不可接收String类型 对于类型限定为String的变量,它既可以接收String类型,也可以接收string类型</p><h2 id="常用数据类型" tabindex="-1"><a class="header-anchor" href="#常用数据类型"><span>常用数据类型</span></a></h2><h3 id="any" tabindex="-1"><a class="header-anchor" href="#any"><span>any</span></a></h3><p>any表示任何数据类型 一个变量被限定为any后表示放弃了类型检查</p><p>加了any限定的变量可以存储任意的数据类型,这样的类型限定是any的显示类型限定 不对一个变量进行类型限定而直接使用let或var声明的变量它们默认也是使用any限定的,这种事any的隐式类型限定</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let a: any</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let b</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>any也可以赋值给任意一个变量 如果一个被限定类型的变量被any变量赋值,那么这个变量就会被破坏</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let a:any</span></span>
<span class="line"><span>a=false</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let b: string</span></span>
<span class="line"><span>x=a</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>不建议这样做</p><h3 id="unknown" tabindex="-1"><a class="header-anchor" href="#unknown"><span>unknown</span></a></h3><p>unknown和any用法类似,但不同的是它不会破坏其他变量的类型限定 可以强制开发者在进行赋值时对类型进行检查</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let a:unknown</span></span>
<span class="line"><span>a=99</span></span>
<span class="line"><span>a=&#39;hello&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let b=string</span></span>
<span class="line"><span>b=a // error</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>即使是到最后一步被unknown限定的变量转换成了对应的类型也不可以被赋值给限定类型相同的变量</p><p><strong>解决方法</strong></p><ol><li>使用if判断 加上一个类型判断后再进行赋值可以成功</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>if(typeof a===&#39;string&#39;){</span></span>
<span class="line"><span>	b=a</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>断言 使用断言的两种写法都可以赋值成功</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>b=a as string</span></span>
<span class="line"><span></span></span>
<span class="line"><span>b=&lt;string&gt;a</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>对于unknow类型也不可以调用一个对象中的方法,除非使用断言</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let a:unknown</span></span>
<span class="line"><span>a=&#39;hello&#39;;</span></span>
<span class="line"><span>a.toUpperCase(); // error</span></span>
<span class="line"><span>(a as string).toUpperCase(); // ok</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>因为未知类型不能确定变量是什么类型,也不知道它是否能调用到正确的函数,因此需要手动做类型检查</p><h3 id="never" tabindex="-1"><a class="header-anchor" href="#never"><span>never</span></a></h3><p>never的含义是：任何值都不是，简言之就是不能有值undefined、null、&quot;&quot;、0都不行 几乎不用never去直接限制变量，因为没有意义 never用在限定函数的返回类型</p><p>当never限定了函数的返回类型后,该函数没有返回值也就不能正常结束 即使一个函数不用return设定返回值当它执行结束后也会返回一个undefined</p><p>在js中正常的函数调用完成都至少会返回一个undefined,但对于一个出现异常或者进入死循环的函数来说,它永远无法执行到函数的末尾,也就不会有返回值 常用于必然抛出异常的函数,当一个函数抛出异常后后面的代码也就不会执行了也就没有了返回值</p><p>never一般是ts自动推断出来的,当一个变量用于达不到一个范围中的代码时,在这个范围中该变量就会被推断为never,如:在无法进入的if判断中</p><h3 id="void" tabindex="-1"><a class="header-anchor" href="#void"><span>void</span></a></h3><p>void用于限定函数的返回值,<mark>调用者不该使用返回值做任何操作</mark></p><p>被void限定返回值的函数只能返回undefiined,不能返回其他值 可以显示或隐式返回undefined</p><p>但void和undefined又不完全相同,当一个函数的返回值被限定为void后对这个函数的返回值做任何操作都是错误的 而默认的undefined是可以使用的</p><h3 id="object" tabindex="-1"><a class="header-anchor" href="#object"><span>object</span></a></h3><p>关于object与Object实际开发中用的相对较少因为范围太大了。</p><p>object能接收的类型是非原始类型 如: 字符串,数字类型,布尔型不可以存 但数组,对象,函数可以存</p><p>对于Object可以存任何能调用到Object方法的值,包括原始类型中的 但null和undefined不可以存</p><h3 id="声明对象类型" tabindex="-1"><a class="header-anchor" href="#声明对象类型"><span>声明对象类型</span></a></h3><p>可以在定义的类型中限定成员属性类型,但限定的成员属性在实例化时必须要传入, 可以加?来可选可不选</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let person{name:string,age?:number};</span></span>
<span class="line"><span>person={name:&#39;tom&#39;}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="声明函数类型" tabindex="-1"><a class="header-anchor" href="#声明函数类型"><span>声明函数类型</span></a></h3><p>相当于函数指针</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let count:(a:number,b:string)=&gt;number</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>限定了count变量只能存储第一个形参为number类型的,第二个形参为string类型的,返回值为number的函数</p><h3 id="声明数组类型" tabindex="-1"><a class="header-anchor" href="#声明数组类型"><span>声明数组类型</span></a></h3><p>限定一个变量只能存什么类型的数组</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let arr1:string[];</span></span>
<span class="line"><span>ler arr2:Array&lt;number&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>arr1只能存字符串数组,arr2只能存数字类型数</p><h3 id="tuple" tabindex="-1"><a class="header-anchor" href="#tuple"><span>tuple</span></a></h3><p>元组（Tuple）是一种特殊的数组类型，可以存储固定数量的元素，并且每个元素的类型是已知的且可以不同。元组用于精确描述一组值的类型，？表示可选元素。</p><h3 id="enum" tabindex="-1"><a class="header-anchor" href="#enum"><span>enum</span></a></h3><p>枚举（enum）可以定义一组命名常量它能增强代码的可读性，也让代码更好维护</p><p>使用enum关键字声明枚举类型</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>enum Diection{</span></span>
<span class="line"><span>	up,</span></span>
<span class="line"><span>	down,</span></span>
<span class="line"><span>	left,</span></span>
<span class="line"><span>	right</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>数字枚举一种最常见的枚举类型，其成员的值会自动递增，且数字枚举还具备反向映射的特点，在下面代码的打印中，可以通过值来获取对应的枚举成员名称。</p><p><strong>字符串枚举</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>enum Direction{</span></span>
<span class="line"><span>	up=&quot;shang&quot;,</span></span>
<span class="line"><span>	down=&quot;xia&quot;,</span></span>
<span class="line"><span>	left=&quot;zuo&quot;,</span></span>
<span class="line"><span>	right=&quot;you&quot;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>字符串枚举丢失了反向映射</p><p><strong>常量枚举</strong> 官方描述：常量枚举是一种特殊枚举类型，它使用const关键字定义，在编译时会被内联，避免生 成一些额外的代码。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const enum Diection{</span></span>
<span class="line"><span>	up,</span></span>
<span class="line"><span>	down,</span></span>
<span class="line"><span>	left,</span></span>
<span class="line"><span>	right</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>所谓“内联”其实就是TypeScript在编译时，会将枚举成员引用替换为它们的实际值，而不是生成 额外的枚举对象。这可以减少生成的JavaScript代码量，并提高运行时性能。</p><h3 id="type" tabindex="-1"><a class="header-anchor" href="#type"><span>type</span></a></h3><h4 id="定义别名" tabindex="-1"><a class="header-anchor" href="#定义别名"><span>定义别名</span></a></h4><p>定义别名,相当于typedef</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>type shuzi=number</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="联合类型" tabindex="-1"><a class="header-anchor" href="#联合类型"><span>联合类型</span></a></h4><p>联合类型是一种高级类型，它表示一个值可以是几种不同类型之一</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>type status=number | string</span></span>
<span class="line"><span>type gender=&#39;男&#39; | &#39;女&#39;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="交叉类型" tabindex="-1"><a class="header-anchor" href="#交叉类型"><span>交叉类型</span></a></h4><p>类似继承 交叉类型（lntersectionTypes）允许将多个类型合并为一个类型。合并后的类型将拥有所有被合并 类型的成员。交叉类型通常用于对象类型。</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//面积</span></span>
<span class="line"><span>type Area ={</span></span>
<span class="line"><span>	height:number; //高</span></span>
<span class="line"><span>	width:number; //宽</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//地址</span></span>
<span class="line"><span>type Address = {</span></span>
<span class="line"><span>	num:number //楼号</span></span>
<span class="line"><span>	cell:number //单元号</span></span>
<span class="line"><span>	room:string //房间号</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>type House = Area &amp; Address</span></span>
<span class="line"><span></span></span>
<span class="line"><span>const house:House={</span></span>
<span class="line"><span>	height:100，//高</span></span>
<span class="line"><span>	width:100，//宽</span></span>
<span class="line"><span>	num:3，//楼号</span></span>
<span class="line"><span>	cel1:4，//单元号</span></span>
<span class="line"><span>	room：&#39;702’//房间号</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>使用type定义的限定函数返回类型的变量如果是void不要求返回值必须为undefined</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>type LogFunc = () =&gt; void</span></span>
<span class="line"><span>const f1:LogFunc = function () {</span></span>
<span class="line"><span>	return 66</span></span>
<span class="line"><span>}    //ok</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这是为了让简写的箭头 函数能够生效</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const src = [1, 2, 3];</span></span>
<span class="line"><span>const dst = [0];</span></span>
<span class="line"><span>src.forEach((el) =&gt; dst.push(el) );</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>对于forEach函数来说传入的回调函数返回值要是void类型,如果回调函数不设置返回值,返回的是undefined符合要求 但当函数体只有一行的时候可以省略大括号将这一行代码作为返回值,此时就不符合void的定义了</p><h1 id="继承" tabindex="-1"><a class="header-anchor" href="#继承"><span>继承</span></a></h1><p>在ts中类之间可以使用extends关键字继承,和java中一样 当子类中有父类的同名函数时需要在前面显式加上override关键字表示重写函数,不加override也会有隐式加上</p><h3 id="属性的简写形式" tabindex="-1"><a class="header-anchor" href="#属性的简写形式"><span>属性的简写形式</span></a></h3><p>而且在ts中类的成员属性也可以使用权限修饰符 权限修饰符的设置和C++一样,但用法和java一样 也多了一个修饰符 readonly只读属性属性无法修改。</p><p>当一个类中的属性有构造器提供初始化时可以简写</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class Person{</span></span>
<span class="line"><span>	constructor(public name: string,public age:number){}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//相当于</span></span>
<span class="line"><span>class Person{</span></span>
<span class="line"><span>	public name,</span></span>
<span class="line"><span>	public age,</span></span>
<span class="line"><span>	constructor(name: string,age:number){}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="抽象类" tabindex="-1"><a class="header-anchor" href="#抽象类"><span>抽象类</span></a></h2><p>可以使用abstract关键字声明抽象类,在抽象类中也是是使用abscract关键字声明抽象函数 和java一样</p><h2 id="接口" tabindex="-1"><a class="header-anchor" href="#接口"><span>接口</span></a></h2><p>使用interface声明接口,使用implements实现接口 和java一样</p><p>interface和type的区别</p><ul><li>相同点：interface 和type都可以用于定义对象结构，两者在许多场景中是可以互换的。</li><li>不同点： interface：更专注于定义对象和类的结构，支持继承、合并。 type：可以定义类型别名、联合类型、交叉类型，但不支持继承和自动合并。</li></ul><h1 id="泛型" tabindex="-1"><a class="header-anchor" href="#泛型"><span>泛型</span></a></h1><p>泛型允许我们在定义函数、类或接口时，使用类型参数来表示天未指定的类型这些参数在具体使用时，才被指定具体的类型，泛型能让同一段代码适用于多种类型，同时仍然保持类型的安全性。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function logData&lt;T&gt;(data:T){</span></span>
<span class="line"><span>	console.log(data)</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>logData&lt;number&gt;(100)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="类型声明文件" tabindex="-1"><a class="header-anchor" href="#类型声明文件"><span>类型声明文件</span></a></h1><p>类型声明文件是TypeScript 中的一种特殊文件，通常以.d.ts作为扩展名。它的主要作用是为现有的JavaScript代码提供类型信息，使得TypeScript能够在使用这些JavaScript库或模块时进行类型检查和提示。</p>`,121)]))}const t=e(l,[["render",d]]),c=JSON.parse('{"path":"/front/ts/1/","title":"1 TypeScript概述","lang":"zh-CN","frontmatter":{"title":"1 TypeScript概述","createTime":"2025/06/18 21:06:48","permalink":"/front/ts/1/"},"readingTime":{"minutes":9.69,"words":2906},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/TypeScript/1 TypeScript概述.md","headers":[]}');export{t as comp,c as data};
